 1	import * as React from 'react';
 2	import _ from 'lodash';
 3	import { Responses } from '../../types/Graph';
 4	import { responseFlags } from '../../utils/ResponseFlags';
 5	import { summaryTitle } from 'pages/Graph/SummaryPanelCommon';
 6	import { Table, TableVariant, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 7	import { kialiStyle } from 'styles/StyleUtils';
 8	
 9	const tableStyle = kialiStyle({
10	  $nest: {
11	    '& tbody > tr:last-child': {
12	      borderBottom: 0
13	    }
14	  }
15	});
16	
17	type ResponseFlagsTableProps = {
18	  responses: Responses;
19	  title: string;
20	};
21	
22	interface Row {
23	  code: string;
24	  flags: string;
25	  key: string;
26	  val: string;
27	}
28	
29	export const ResponseFlagsTable: React.FC<ResponseFlagsTableProps> = (props: ResponseFlagsTableProps) => {
30	  const getRows = (responses: Responses): Row[] => {
31	    const rows: Row[] = [];
32	    _.keys(responses).forEach(code => {
33	      _.keys(responses[code].flags).forEach(f => {
34	        rows.push({ key: `${code} ${f}`, code: code, flags: f, val: responses[code].flags[f] });
35	      });
36	    });
37	
38	    return rows;
39	  };
40	
41	  const getTitle = (flags: string): string => {
42	    return flags
43	      .split(',')
44	      .map(flagToken => {
45	        flagToken = flagToken.trim();
46	        const flag = responseFlags[flagToken];
47	        return flagToken === '-' ? '' : `[${flagToken}] ${flag ? flag.help : 'Unknown Flag'}`;
48	      })
49	      .join('\n');
50	  };
51	
52	  const rows = getRows(props.responses);
53	
54	  return (
55	    <>
56	      <div className={summaryTitle}>{props.title}</div>
57	
58	      <Table variant={TableVariant.compact} className={tableStyle}>
59	        <Thead>
60	          <Tr key="table-header">
61	            <Th dataLabel="Code" textCenter>
62	              Code
63	            </Th>
64	            <Th dataLabel="Flags" textCenter>
65	              Flags
66	            </Th>
67	            <Th dataLabel="% Req" textCenter>
68	              % Req
69	            </Th>
70	          </Tr>
71	        </Thead>
72	
73	        <Tbody>
74	          {rows.map(row => (
75	            <Tr key={row.key}>
76	              <Td dataLabel="Code" textCenter>
77	                {row.code}
78	              </Td>
79	              <Td dataLabel="Flags" title={getTitle(row.flags)} textCenter>
80	                {row.flags}
81	              </Td>
82	              <Td dataLabel="% Req" textCenter>
83	                {row.val}
84	              </Td>
85	            </Tr>
86	          ))}
87	        </Tbody>
88	      </Table>
89	    </>
90	  );
91	};

